import { useEffect, useState } from "react";
import { NavBar } from "./NavBar"; // NavBar za gosta
import pattern from "../slike/pattern4.jpg";

export function RezervacijeGost() {
    const [rezervacije, setRezervacije] = useState([]);
    const [filter, setFilter] = useState("ALL");

    // Čitanje userId iz cookie-ja
    const getCookie = (name) => {
        const match = document.cookie.match(new RegExp("(^| )" + name + "=([^;]+)"));
        return match ? match[2] : null;
    };
    const userId = getCookie("userId");

    useEffect(() => {
        if (!userId) return;

        // Dohvati samo rezervacije ulogovanog gosta
        fetch(`http://localhost:8080/reservations/guest/${userId}`)
            .then(res => res.json())
            .then(data => {
                if (data?.data?.values) setRezervacije(data.data.values);
            })
            .catch(err => console.error("Greška pri učitavanju rezervacija:", err));
    }, [userId]);

    const filtriraneRezervacije = filter === "ALL"
        ? rezervacije
        : rezervacije.filter(r => r.statusRezervacije === filter);

    const statusi = ["ALL", "PENDING", "CONFIRMED", "CHECKED_IN", "CHECKED_OUT", "CANCELLED"];

    return (
        <>
            <NavBar />
            <div style={{
                backgroundImage: `url(${pattern})`,
                backgroundSize: "cover",
                backgroundPosition: "center",
                minHeight: "100vh",
                padding: "40px",
            }}>
                <h2 style={{
                    textAlign: "center",
                    color: "white",
                    backgroundColor: "rgba(215, 96, 255, 0.6)",
                    padding: "15px 30px",
                    borderRadius: "10px",
                    display: "inline-block",
                }}>
                    Moje rezervacije
                </h2>

                {/* Filter dugmad */}
                <div style={{ display: "flex", justifyContent: "center", marginBottom: "20px" }}>
                    {statusi.map(s => (
                        <button
                            key={s}
                            onClick={() => setFilter(s)}
                            style={{
                                margin: "0 8px",
                                padding: "8px 16px",
                                backgroundColor: filter === s ? "#ce7affff" : "#ffffffff",
                                color: filter === s ? "white" : "black",
                                border: "none",
                                borderRadius: "6px",
                                cursor: "pointer",
                            }}
                        >
                            {s === "ALL" ? "Sve" : s.replace("_", " ")}
                        </button>
                    ))}
                </div>

                {/* Kartice rezervacija */}
                <div style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))",
                    gap: "20px",
                    padding: "0 20px",
                }}>
                    {rezervacije.length > 0 ? (
                        rezervacije.map(rez => (
                            <div key={rez.idRezervacija} style={{
                                backgroundColor: "#f7f9fc",
                                borderRadius: "10px",
                                padding: "20px",
                                boxShadow: "0px 2px 8px rgba(0,0,0,0.1)",
                            }}>
                                <h3>Rezervacija #{rez.idRezervacija}</h3>
                                <p><strong>Soba:</strong> {rez.soba?.brojSobe}</p>
                                <p><strong>Datum prijave:</strong> {rez.datumPrijave}</p>
                                <p><strong>Datum odjave:</strong> {rez.datumOdjave}</p>
                                <p><strong>Status:</strong> {rez.statusRezervacije === "PENDING" ? "Zahtevano" : "Odobreno"}</p>
                                <p><strong>Broj osoba:</strong> {rez.brojOsoba}</p>
                                <p><strong>Ukupan iznos:</strong> {rez.ukupanIznos} RSD</p>
                            </div>
                        ))
                    ) : (
                        <p style={{ textAlign: "center", width: "100%" }}>
                            Nemate rezervacija.
                        </p>
                    )}
                </div>

            </div>
        </>
    );
}
